module  RefModule (
    data_out,                      
    clk,                           
    data_in,                       
    rst                            
);
output              data_out;      
input               clk;          
input               data_in;      
input               rst;          
reg  [1:0] obf_data_sync;
always @(posedge clk or posedge rst)
  if (rst) obf_data_sync <=  2'b00;
  else     obf_data_sync <=  {obf_data_sync[0], data_in};
assign     data_out   =   obf_data_sync[1];
endmodule
